const <gap:target id="auth-middleware-name">verifyAuthToken</gap:target> = (<gap:target id="auth-req-param">req</gap:target>, <gap:target id="auth-res-param">res</gap:target>, <gap:target id="auth-next-param">next</gap:target>) => {
  const <gap:target id="auth-header-name">authHeader</gap:target> = <gap:target id="auth-req-headers-access">req.headers['authorization']</gap:target>;
  const <gap:target id="auth-api-key-name">apiKey</gap:target> = req.headers['x-api-key'];
  const <gap:target id="auth-token-prefix">tokenPrefix</gap:target> = '<gap:target id="auth-bearer-prefix">Bearer </gap:target>';
  const <gap:target id="expected-token">expectedToken</gap:target> = <gap:target id="expected-token-value">secrettoken</gap:target>;
  const <gap:target id="expected-api-key">expectedApiKey</gap:target> = 'secrettoken';

  const <gap:target id="auth-bearer-valid-check">bearerValid</gap:target> = <gap:target id="auth-header-present-check">authHeader</gap:target> && <gap:target id="auth-header-prefix-check">authHeader.startsWith(tokenPrefix)</gap:target> && <gap:target id="auth-token-match-check">authHeader.slice(tokenPrefix.length) === expectedToken</gap:target>;
  const <gap:target id="auth-api-key-valid-check">apiKeyValid</gap:target> = typeof apiKey === 'string' && apiKey === expectedApiKey;

  if (!<gap:target id="auth-bearer-valid-check-2">bearerValid</gap:target> && !<gap:target id="auth-api-key-valid-check-2">apiKeyValid</gap:target>) {
    return <gap:target id="auth-missing-return">res.status(401).json({ message: 'Missing or invalid authorization token' })</gap:target>;
  }

  <gap:target id="auth-next-call">next()</gap:target>;
};
